const t="/api/usuarios";async function s(o){const r=new URLSearchParams;Object.entries(o).forEach(([e,a])=>{a!==void 0&&a!==""&&r.append(e,String(a))});const n=await fetch(`${t}?${r.toString()}`);if(!n.ok)throw new Error("Error al obtener usuarios");return n.json()}async function i(o){const r=await fetch(`${t}/${o}`);if(!r.ok)throw new Error("Usuario no encontrado");return r.json()}async function c(o){const r=await fetch(t,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(o)});if(!r.ok)throw new Error("Error al crear usuario");return r.json()}async function u(o,r){const n=await fetch(`${t}/${o}`,{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(r)});if(!n.ok)throw new Error("Error al actualizar usuario");return n.json()}export{i as a,c,s as g,u};
